// TestNovelBulkPreviewNoNetwork verifies the default (no --apply) path prints a
// plan and exits 0 without touching the network, even under the verifier.
func TestNovelBulkPreviewNoNetwork(t *testing.T) {
	t.Setenv(cliutil.VerifyEnvVar, "1")
	cmd := RootCmd()
	var out bytes.Buffer
	cmd.SetArgs([]string{"bulk", "move", "--ids", "1,2", "--set", "pipeline_stage_id=9"})
	cmd.SetOut(&out)
	cmd.SetErr(io.Discard)
	if err := cmd.Execute(); err != nil {
		t.Fatalf("bulk preview error = %v", err)
	}
	if !strings.Contains(out.String(), "PREVIEW") {
		t.Errorf("preview output missing PREVIEW marker: %q", out.String())
	}
}

func TestNovelBulkRejectsNonNumericID(t *testing.T) {
	// Path-traversal / non-numeric ids must be rejected, not concatenated
	// into the request path.
	for _, bad := range []string{"../people/5", "88?x=1", "88/foo", "abc"} {
		if _, err := resolveBulkIDs("", bad); err == nil {
			t.Errorf("resolveBulkIDs(%q) = nil error, want rejection", bad)
		}
	}
	// Valid numeric ids still pass.
	ids, err := resolveBulkIDs("", "88,90, 91")
	if err != nil {
		t.Fatalf("resolveBulkIDs valid ids: unexpected error %v", err)
	}
	if len(ids) != 3 {
		t.Errorf("got %d ids, want 3: %v", len(ids), ids)
	}
}
